/* ---- ELU 活性化関数 ---- */
static inline float elu(float x) {
    return x >= 0.0f ? x : (expf(x) - 1.0f);
}

/* ---- 推論関数 ---- */
float policy_infer(const float* obs) {
    float buf_a[128];
    float buf_b[128];
    const float* in_ptr  = obs;
    float*       out_ptr = buf_a;

    /* layer0: 3 -> 128 */
    for (int o = 0; o < 128; o++) {
        float sum = b0[o];
        for (int j = 0; j < 3; j++) {
            sum += W0[o * 3 + j] * in_ptr[j];
        }
        out_ptr[o] = elu(sum);
    }

    in_ptr  = buf_a;
    out_ptr = buf_b;

    /* layer1: 128 -> 128 */
    for (int o = 0; o < 128; o++) {
        float sum = b1[o];
        for (int j = 0; j < 128; j++) {
            sum += W1[o * 128 + j] * in_ptr[j];
        }
        out_ptr[o] = elu(sum);
    }

    in_ptr  = buf_b;
    out_ptr = buf_a;

    /* layer2: 128 -> 128 */
    for (int o = 0; o < 128; o++) {
        float sum = b2[o];
        for (int j = 0; j < 128; j++) {
            sum += W2[o * 128 + j] * in_ptr[j];
        }
        out_ptr[o] = elu(sum);
    }

    in_ptr  = buf_a;
    out_ptr = buf_b;

    /* layer3: 128 -> 1 */
    for (int o = 0; o < 1; o++) {
        float sum = b3[o];
        for (int j = 0; j < 128; j++) {
            sum += W3[o * 128 + j] * in_ptr[j];
        }
        out_ptr[o] = sum;  /* 最終層: 線形（活性化なし）*/
    }

    return out_ptr[0];  /* ACT_DIM=1 なのでスカラーで返す */
}